from piece import Piece

class Board:
    def initialize_board(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        # Initialize black pieces
        for i in range(3):
            for j in range(0, 8, 2):
                self.board[i][j] = Piece('B', (i, j))
        # Initialize white pieces
        for i in range(5, 8):
            for j in range(1, 9, 2):
                self.board[i][j] = Piece('W', (i, j))

    def get_piece(self, position):
        return self.board[position[0]][position[1]]

    def move_piece(self, from_pos, to_pos):
        piece = self.get_piece(from_pos)
        if piece:
            self.board[to_pos[0]][to_pos[1]] = piece
            self.board[from_pos[0]][from_pos[1]] = None
            piece.position = to_pos

    def capture_piece(self, capture_positions):
        for pos in capture_positions:
            if self.get_piece(pos):
                self.board[pos[0]][pos[1]] = None

    def king_piece(self, position):
        piece = self.get_piece(position)
        if piece and not piece.is_king and ((piece.color == 'B' and position[0] == 7) or (piece.color == 'W' and position[0] == 0)):
            piece.is_king = True
```

