from board import Board
from move_validator import MoveValidator

class GameLogic:
    def __init__(self):
        self.board = Board()
        self.current_player = 'B'
        self.move_validator = MoveValidator(self.board)

    def make_move(self, from_pos, to_pos):
        if self.move_validator.is_valid_move(from_pos, to_pos):
            self.board.move_piece(from_pos, to_pos)
            # Check for captures (to be implemented)
            self.switch_player()

    def switch_player(self):
        self.current_player = 'W' if self.current_player == 'B' else 'B'

    def check_win_condition(self):
        # Simple win condition logic (to be expanded with valid game states)
        black_pieces = [p for row in self.board.board for p in row if p and p.color == 'B']
        white_pieces = [p for row in self.board.board for p in row if p and p.color == 'W']

        if not black_pieces:
            return 'White wins'
        elif not white_pieces:
            return 'Black wins'
        else:
            return None
